document.addEventListener("DOMContentLoaded",function(){const e=document.getElementById("footer-placeholder");if(e){const o=window.location.pathname.includes("blog-posts/");fetch(o?"../components/footer.html":"components/footer.html").then(e=>e.text()).then(t=>{o&&(t=(t=t.replace(/src="assets\//g,'src="../assets/')).replace(/href="([^"]*\.html)"/g,'href="../$1"')),e.innerHTML=t}).catch(t=>{console.error("Error loading footer:",t);e.innerHTML='\n                    <section class="section">\n                        <div class="container">\n                            <div class="footer-content">\n                                <div class="footer-section">\n                                    <div class="footer-logo-section">\n                                        <div class="footer-logo-container footer-logo-masked"></div>\n                                        <h3>Elemento</h3>\n                                    </div>\n                                    <p>Vendor-neutral, high-performance cloud platform that\'s cost-effective, green, and self-hostable.</p>\n                                </div>\n                            </div>\n                            <div class="footer-bottom">\n                                <p>&copy; 2024 Elemento. All rights reserved.</p>\n                            </div>\n                        </div>\n                    </section>\n                ';const n=e.querySelector(".footer-logo-masked");if(n){const e=o?"../assets/logos/Elemento.svg":"assets/logos/Elemento.svg";n.style.filter="brightness(0) saturate(100%)",n.style.mask=`url('${e}') no-repeat center`,n.style.maskSize="contain",n.style.webkitMask=`url('${e}') no-repeat center`,n.style.webkitMaskSize="contain",n.style.backgroundColor="currentColor",n.style.color="inherit"}})}});